#include <iostream>
using namespace std;

class MyException {
public:
    string msg;
    MyException(string m) : msg(m) {}
};

int main() {
    try {
        throw MyException("Custom Error");
    } catch (MyException &e) {
        cout << e.msg << endl;
    }
    return 0;
}

#include <iostream>
#include <stdexcept>
using namespace std;

int main() {
    try {
        throw runtime_error("Something went wrong");
    } catch (exception &e) {
        cout << "Std Exception: " << e.what() << endl;
    }
    return 0;
}

try {
    // ...
} catch (...) {
    cout << "Handling partially...\n";
    throw; // Re-throws the current exception
}

void func() noexcept {
    // This function guarantees not to throw exceptions
}

#include <iostream>
#include <exception>
using namespace std;

class InvalidAgeException : public exception {
public:
    const char* what() const noexcept override {
        return "Age cannot be negative!";
    }
};

int main() {
    try {
        throw InvalidAgeException();
    } catch (exception &e) {
        cout << e.what() << endl;
    }
    return 0;
}
